import { SearchField } from '@tale-ui/react/search-field';
import { Icon } from '@tale-ui/react/icon';
import { X } from 'lucide-react';

export function SearchFieldExample() {
  return (
    <SearchField.Root defaultValue="Keyboard">
      <SearchField.Label>Search Products</SearchField.Label>
      <SearchField.Input placeholder="Type to search..." />
      <SearchField.ClearButton>
        <Icon icon={X} size="sm" />
      </SearchField.ClearButton>
    </SearchField.Root>
  );
}
